#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string alienOrder(vector<string>& words) {
        if (words.empty()) return "";
        int k = 0;
        unordered_set<char> set;
        for (const auto& word : words) {
            for (char c : word) {
                set.insert(c);
            }
        }
        k = set.size();
        unordered_map<char, vector<char>> graph;
        unordered_map<char, int> indegree;
        for (char c : set) {
            indegree[c] = 0;
        }
        for (int i = 0; i < words.size() - 1; ++i) {
            const string& w1 = words[i];
            const string& w2 = words[i + 1];
            int j = 0;
            while (j < w1.size() && j < w2.size() && w1[j] == w2[j]) {
                ++j;
            }
            if (j < w1.size() && j == w2.size()) {
                return "IMPOSSIBLE";
            }
            if (j == w1.size() && j == w2.size()) {
                continue;
            }
            if (graph.find(w1[j]) == graph.end()) {
                graph[w1[j]] = {};
            }
            if (find(graph[w1[j]].begin(), graph[w1[j]].end(), w2[j]) == graph[w1[j]].end()) {
                graph[w1[j]].push_back(w2[j]);
                ++indegree[w2[j]];
            }
        }
        queue<char> q;
        for (const auto& pair : indegree) {
            if (pair.second == 0) {
                q.push(pair.first);
            }
        }
        string res;
        while (!q.empty()) {
            char c = q.front();
            q.pop();
            res += c;
            if (graph.find(c) != graph.end()) {
                for (char neighbor : graph[c]) {
                    --indegree[neighbor];
                    if (indegree[neighbor] == 0) {
                        q.push(neighbor);
                    }
                }
            }
        }
        if (res.size() != k) {
            return "IMPOSSIBLE";
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int k;
    cin >> k;
    int n;
    cin >> n;
    vector<string> words(n);
    for (int i = 0; i < n; ++i) {
        cin >> words[i];
    }
    Solution sol;
    string ans = sol.alienOrder(words);
    cout << ans << '\n';
    return 0;
}
